import React from 'react';
import PropTypes from 'prop-types';
import { withStyles } from '@material-ui/core/styles';
import Paper from '@material-ui/core/Paper';
import Fade from '@material-ui/core/Fade';
import Typography from '@material-ui/core/Typography';
import Tabs from '@material-ui/core/Tabs';
import Tab from '@material-ui/core/Tab';



const styles = theme => ({
  root: {
    height: 180,
  },
  paper: {
    margin: theme.spacing.unit*2,
  },
});

const domData = [
  {
    id: 1,
    title: 'Profile',
    dis:[
    'I like Frontend and simple code ',
    'MarkupLanguage ★★',
    'React ★★',
    'Node.js ★',

    ]
  },
  {
    id:2,
    title:'Product',
    dis:[
    '2016~AnimeSite of Roboharf',
    '2017~Graduation:Camera monitaring by RaspberryPi ',
    '2018~ShortBoard.jp'
    ]
   },
  {
    id:3,
    title:'Work',
    dis:[
    '2017/4~Graduation'
    ]
   },
];
 
class SimpleFade extends React.Component {
  state = {
    checked: false,
    value: 0,
  };
  
  handleChange = (event, value) => {
    this.setState({ value });
  };
  

  componentDidMount(){
    this.setState({checked:true})
  };

  render() {
    const { classes } = this.props;
    const { checked } = this.state;
    console.log(this.state.value)

    return (
      <div className={classes.root}>
       <Tabs
          value={this.state.value}
          onChange={this.handleChange}
          indicatorColor="primary"
          textColor="primary"
          centered
        >
        <Tab label="Profile" />
        <Tab label="Product" />
        <Tab label="Work" />
        </Tabs>
        <Fade in={checked}>
        <Paper elevation={1} className={classes.paper}>
        <Typography variant="headline" component="h3">
        {domData[this.state.value].title}
        </Typography>
        {domData[this.state.value].dis.map((d,idx)=> (
        <Typography component="p" key={idx}>
        {d}
        </Typography>
        ))}
        </Paper>
        </Fade>
      </div>
    );
  }
}

SimpleFade.propTypes = {
  classes: PropTypes.object.isRequired,
};

export default withStyles(styles)(SimpleFade);


